example.code:
# .env.tpl — committed to git, no actual secrets
DATABASE_URL={{ op://ServerVault/Database/url }}
ANTHROPIC_API_KEY={{ op://ServerVault/Anthropic/api-key }}
JWT_SECRET={{ op://ServerVault/JWT/secret }}
TELEGRAM_BOT_TOKEN={{ op://ServerVault/TelegramBot/token }}
LOG_LEVEL=INFO
DEBUG=false

# Generate .env from template (run at deploy time or after rotation)
export OP_SERVICE_ACCOUNT_TOKEN="ops_xxxxxxxxxxxx"
op inject -i ~/workspace/.env.tpl -o ~/workspace/.env
chmod 600 ~/workspace/.env
